import type { Metadata } from "next";
import PrescriptionOrderEntry from "./PrescriptionOrderEntry";

export const metadata: Metadata = {
  title: "処方オーダ入力 | ぐんじょう 電子カルテ",
  description:
    "医師が処方箋を作成する処方オーダ入力画面。患者コンテキスト（患者ID / 氏名 / 年齢・体重 / 病棟、アレルギー歴・腎機能(eGFR/Cr)・肝機能・併用薬）の上で、採用薬フォーミュラリから薬剤を検索し、用量・剤形・投与経路・用法・日数・開始日を設定。アレルギー警告（交差反応含む）・薬物相互作用（禁忌/重大/中等度）・用量チェック（過量/過少/範囲内・腎機能による用量調整）の3つの安全チェックを実施し、規制医薬品（麻薬・向精神薬）は2人署名の上で処方セットを確定・署名します。",
};

export default function PrescriptionPage() {
  return <PrescriptionOrderEntry />;
}

// ── HAND-ROLLED (FINDINGS-56, 🟠) ─────────────────────────────────────────────
// The dose-range / safe-range flag. @gunjo/ui ships no `ReferenceValue` /
// `RangeFlag` / `flagValue()` primitive, so this is built from `Badge` (tone) +
// tabler icons (shape, NOT colour-only) + sr-only text. SAME gap as #54 vitals
// and #55 labs — the 3rd consecutive medical screen to hand-roll it. Ideal
// library API:
//   <ReferenceValue value={dose} low={..} high={..} unit="mg" /> deriving
//   flag + tone + accessible text via a pure `flagValue(value, {low, high})`.
import * as React from "react";
import {
  IconChevronsUp,
  IconChevronDown,
  IconCircleCheck,
} from "@tabler/icons-react";
import { Badge } from "@gunjo/ui";
import type { DoseFlagCode, DoseFlagResult } from "./rx-data";

const FLAG_ICON: Record<DoseFlagCode, React.ComponentType<{ className?: string }>> = {
  OK: IconCircleCheck,
  H: IconChevronsUp,
  L: IconChevronDown,
};

const TONE_TO_VARIANT: Record<
  DoseFlagResult["tone"],
  "success" | "warning" | "destructive"
> = {
  success: "success",
  warning: "warning",
  destructive: "destructive",
};

export function DoseRangeFlag({
  result,
  className,
}: {
  result: DoseFlagResult;
  className?: string;
}) {
  const Glyph = FLAG_ICON[result.code];
  return (
    <Badge variant={TONE_TO_VARIANT[result.tone]} className={`gap-1 px-2 ${className ?? ""}`}>
      <Glyph className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
      {/* meaning rides on icon + code + text — never colour alone */}
      <span aria-hidden="true">{result.label}</span>
      <span className="sr-only">{result.srText}</span>
    </Badge>
  );
}

"use client";

import * as React from "react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Checkbox,
  Combobox,
  type ComboboxOption,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  EmptyState,
  Input,
  NumberInput,
  RadioGroup,
  RadioGroupItem,
  Select,
  Separator,
  Statistic,
  Switch,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  Textarea,
  cn,
} from "@gunjo/ui";
import {
  IconAlertTriangleFilled,
  IconBan,
  IconCircleCheck,
  IconClipboardList,
  IconDroplet,
  IconLock,
  IconPencilPlus,
  IconPill,
  IconShieldHalfFilled,
  IconTrash,
  IconVaccine,
  IconWritingSign,
  IconActivityHeartbeat,
  IconFlask,
} from "@tabler/icons-react";
import {
  FORMULARY,
  FREQ_OPTIONS,
  NOW_LABEL,
  PATIENT,
  PRESCRIBER,
  ROUTE_OPTIONS,
  SEVERITY_RANK,
  SEVERITY_TONE,
  TODAY,
  allergyHits,
  doseFlag,
  interactionHits,
  type FormularyDrug,
  type InteractionHit,
  type Route,
  type RxLine,
} from "./rx-data";
import { DoseRangeFlag } from "./DoseRangeFlag";

type IconType = React.ComponentType<React.SVGProps<SVGSVGElement>>;
const ROUTE_ICON: Record<Route, IconType> = {
  内服: IconPill,
  点滴静注: IconDroplet,
  皮下注: IconVaccine,
  筋注: IconVaccine,
  外用: IconPill,
};

const CATEGORY_LABEL = {
  通常: null,
  麻薬: "麻薬（要2人署名）",
  向精神薬: "向精神薬（要2人署名）",
} as const;

interface CoSign {
  signerId: string;
  reason: string;
}

let keySeq = 0;
function nextKey() {
  keySeq += 1;
  return `rx-${keySeq}`;
}

export default function PrescriptionOrderEntry() {
  // 処方セット（order set）
  const [lines, setLines] = React.useState<RxLine[]>([]);

  // 確定・署名
  const [signed, setSigned] = React.useState(false);

  // アレルギー / 禁忌相互作用の確認（acknowledge）— key は line.key。
  const [ackedAllergy, setAckedAllergy] = React.useState<Set<string>>(new Set());
  const [ackedInteraction, setAckedInteraction] = React.useState<Set<string>>(new Set());

  // 用量オーバーライド（過量/過少を理由付きで許容）。 key → reason
  const [doseOverride, setDoseOverride] = React.useState<Record<string, string>>({});

  // 規制医薬品の2人署名。 key → CoSign
  const [coSigns, setCoSigns] = React.useState<Record<string, CoSign>>({});

  // co-sign composer
  const [coSignFor, setCoSignFor] = React.useState<RxLine | null>(null);

  // ── 追加フォームの状態 ──────────────────────────────────────────────────────
  const [pickId, setPickId] = React.useState<string>("");
  const picked = FORMULARY.find((d) => d.id === pickId) ?? null;
  const [form, setForm] = React.useState<string>("");
  const [dose, setDose] = React.useState<number>(0);
  const [route, setRoute] = React.useState<Route>("内服");
  const [freq, setFreq] = React.useState<string>(FREQ_OPTIONS[4]);
  const [days, setDays] = React.useState<number>(7);

  // 薬剤を選んだら既定値をプリフィル。
  React.useEffect(() => {
    if (!picked) return;
    setForm(picked.forms[0]);
    setDose(picked.usualLow);
    setRoute(picked.defaultRoute);
    setFreq(picked.defaultFreq);
  }, [picked]);

  const comboOptions: ComboboxOption[] = React.useMemo(
    () =>
      FORMULARY.map((d) => ({
        value: d.id,
        label: `${d.generic}（${d.brand}）`,
        group: d.category === "通常" ? "通常薬" : "規制医薬品（麻薬・向精神薬）",
        keywords: [...d.keywords, d.generic, d.brand, d.category],
      })),
    []
  );

  // 追加フォームのライブ安全チェック（追加前プレビュー）
  const draftDoseFlag = picked ? doseFlag(picked, dose, PATIENT.egfr) : null;
  const draftAllergy = picked ? allergyHits(picked, PATIENT) : [];
  const draftInteractions = picked
    ? interactionHits(picked, PATIENT, lines.map((l) => l.drug.generic))
    : [];

  function addLine() {
    if (!picked) return;
    const line: RxLine = {
      key: nextKey(),
      drug: picked,
      form,
      dose,
      route,
      freq,
      days,
      startDate: TODAY,
    };
    setLines((prev) => [...prev, line]);
    setSigned(false);
    // フォームをリセット
    setPickId("");
    setForm("");
    setDose(0);
    setDays(7);
  }

  function removeLine(key: string) {
    setLines((prev) => prev.filter((l) => l.key !== key));
    setSigned(false);
    setAckedAllergy((s) => dropKey(s, key));
    setAckedInteraction((s) => dropKey(s, key));
    setDoseOverride((m) => {
      const { [key]: _drop, ...rest } = m;
      return rest;
    });
    setCoSigns((m) => {
      const { [key]: _drop, ...rest } = m;
      return rest;
    });
  }

  // ── 各 line の安全評価 ──────────────────────────────────────────────────────
  type LineEval = {
    line: RxLine;
    allergy: ReturnType<typeof allergyHits>;
    interactions: InteractionHit[];
    dose: ReturnType<typeof doseFlag>;
    needsAllergyAck: boolean;
    needsInteractionAck: boolean; // 禁忌のみブロック対象
    needsDoseResolve: boolean; // 過量(H)はブロック対象、過少(L)は注意
    needsCoSign: boolean;
  };

  const evals: LineEval[] = React.useMemo(() => {
    return lines.map((line, idx) => {
      const otherGenerics = lines
        .filter((_, i) => i !== idx)
        .map((l) => l.drug.generic);
      const allergy = allergyHits(line.drug, PATIENT);
      const interactions = interactionHits(line.drug, PATIENT, otherGenerics);
      const d = doseFlag(line.drug, line.dose, PATIENT.egfr);
      const hasContraindication = interactions.some((i) => i.severity === "禁忌");
      return {
        line,
        allergy,
        interactions,
        dose: d,
        needsAllergyAck: allergy.length > 0,
        needsInteractionAck: hasContraindication,
        needsDoseResolve: d.code === "H", // 過量は要解決
        needsCoSign: line.drug.category !== "通常",
      };
    });
  }, [lines]);

  // ── サインオフをブロックする未解決項目 ─────────────────────────────────────
  const blockers = React.useMemo(() => {
    const list: { kind: string; line: RxLine; detail: string }[] = [];
    for (const e of evals) {
      if (e.needsAllergyAck && !ackedAllergy.has(e.line.key)) {
        list.push({
          kind: "アレルギー",
          line: e.line,
          detail: `${e.line.drug.generic}：アレルギー警告が未確認です。`,
        });
      }
      if (e.needsInteractionAck && !ackedInteraction.has(e.line.key)) {
        list.push({
          kind: "禁忌相互作用",
          line: e.line,
          detail: `${e.line.drug.generic}：禁忌の薬物相互作用が未確認です。`,
        });
      }
      if (e.needsDoseResolve && !doseOverride[e.line.key]) {
        list.push({
          kind: "過量",
          line: e.line,
          detail: `${e.line.drug.generic}：用量が安全範囲を超えています。減量するか理由付きで許可してください。`,
        });
      }
      if (e.needsCoSign && !coSigns[e.line.key]) {
        list.push({
          kind: "2人署名",
          line: e.line,
          detail: `${e.line.drug.generic}（${e.line.drug.category}）：規制医薬品のため2人目の署名が必要です。`,
        });
      }
    }
    return list;
  }, [evals, ackedAllergy, ackedInteraction, doseOverride, coSigns]);

  const canSign = lines.length > 0 && blockers.length === 0 && !signed;

  // 集計
  const allergyCount = evals.filter((e) => e.needsAllergyAck).length;
  const contraindicationCount = evals.filter((e) => e.needsInteractionAck).length;
  const doseIssueCount = evals.filter((e) => e.dose.code !== "OK").length;
  const controlledCount = evals.filter((e) => e.needsCoSign).length;

  return (
    <main className="min-h-screen bg-muted/20 py-5 sm:py-6">
      <div className="mx-auto w-full max-w-6xl space-y-5 px-4 sm:px-6">
        {/* ───────────────────────── ページ見出し ───────────────────────── */}
        <header className="space-y-1">
          <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
            処方 / 処方オーダ入力 — CPOE
          </p>
          <div className="flex flex-wrap items-center gap-2">
            <h1 className="flex items-center gap-2 text-2xl font-bold tracking-tight">
              <IconPencilPlus className="h-7 w-7 text-primary" aria-hidden="true" />
              処方オーダ入力
            </h1>
            {signed ? (
              <Badge variant="success" className="gap-1">
                <IconCircleCheck className="h-3.5 w-3.5" aria-hidden="true" />
                署名済
              </Badge>
            ) : lines.length === 0 ? (
              <Badge variant="outline">未作成</Badge>
            ) : (
              <Badge variant="warning">作成中</Badge>
            )}
          </div>
          <p className="text-sm text-muted-foreground">
            採用薬を検索して用量・経路・用法・日数を設定し、アレルギー・相互作用・用量の3点を安全チェック。規制医薬品は2人署名のうえ処方セットを確定・署名します（現在 {NOW_LABEL}）。
          </p>
        </header>

        {/* ───────────────────────── 患者コンテキスト ───────────────────────── */}
        <PatientBanner />

        {/* ───────────────────────── 安全サマリ ───────────────────────── */}
        <section aria-labelledby="safety-summary-heading">
          <h2 id="safety-summary-heading" className="sr-only">
            安全チェックサマリ
          </h2>
          <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
            <Statistic
              label="アレルギー警告"
              value={`${allergyCount} 件`}
              tone={allergyCount > 0 ? "negative" : "positive"}
              trend={allergyCount > 0 ? "up" : "flat"}
              change={allergyCount > 0 ? "要確認" : "なし"}
            />
            <Statistic
              label="禁忌相互作用"
              value={`${contraindicationCount} 件`}
              tone={contraindicationCount > 0 ? "negative" : "positive"}
              trend={contraindicationCount > 0 ? "up" : "flat"}
              change={contraindicationCount > 0 ? "ブロック" : "なし"}
            />
            <Statistic
              label="用量フラグ"
              value={`${doseIssueCount} 件`}
              tone={doseIssueCount > 0 ? "negative" : "positive"}
              change={doseIssueCount > 0 ? "過量/過少" : "範囲内"}
            />
            <Statistic
              label="規制医薬品"
              value={`${controlledCount} 件`}
              tone={controlledCount > 0 ? "neutral" : "positive"}
              change={controlledCount > 0 ? "2人署名要" : "なし"}
            />
          </div>
        </section>

        <div className="grid grid-cols-1 gap-5 lg:grid-cols-[minmax(0,1fr)_minmax(340px,440px)]">
          {/* ─────────────── 左：処方セットのレビュー ─────────────── */}
          <div className="order-2 space-y-5 lg:order-1">
            <OrderSetCard
              evals={evals}
              ackedAllergy={ackedAllergy}
              ackedInteraction={ackedInteraction}
              doseOverride={doseOverride}
              coSigns={coSigns}
              signed={signed}
              onRemove={removeLine}
              onAckAllergy={(k) => setAckedAllergy((s) => addKey(s, k))}
              onAckInteraction={(k) => setAckedInteraction((s) => addKey(s, k))}
              onSetDoseOverride={(k, r) =>
                setDoseOverride((m) => ({ ...m, [k]: r }))
              }
              onClearDoseOverride={(k) =>
                setDoseOverride((m) => {
                  const { [k]: _d, ...rest } = m;
                  return rest;
                })
              }
              onOpenCoSign={(line) => setCoSignFor(line)}
            />

            {/* サインオフ・アクション */}
            <SignOffCard
              lines={lines}
              blockers={blockers}
              canSign={canSign}
              signed={signed}
              onSign={() => setSigned(true)}
              onClear={() => {
                setLines([]);
                setSigned(false);
                setAckedAllergy(new Set());
                setAckedInteraction(new Set());
                setDoseOverride({});
                setCoSigns({});
              }}
            />
          </div>

          {/* ─────────────── 右：処方薬の追加 ─────────────── */}
          <div className="order-1 lg:order-2">
            <Card className="lg:sticky lg:top-5">
              <CardHeader className="pb-3">
                <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                  <IconClipboardList className="h-5 w-5" aria-hidden="true" />
                  処方薬の追加
                </CardTitle>
                <CardDescription>
                  採用薬フォーミュラリから検索して用法用量を設定します。
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                {/* フォーミュラリ検索 */}
                <div className="space-y-1.5">
                  <label id="drug-pick-label" className="text-sm font-medium leading-none">
                    薬剤（一般名 / 商品名で検索）
                  </label>
                  <Combobox
                    options={comboOptions}
                    value={pickId}
                    onValueChange={setPickId}
                    placeholder="薬剤を選択…"
                    searchPlaceholder="一般名・商品名・効能で検索"
                    emptyMessage="該当する採用薬がありません"
                    clearable
                    aria-labelledby="drug-pick-label"
                  />
                </div>

                {picked ? (
                  <div className="space-y-4">
                    {picked.category !== "通常" ? (
                      <Badge variant="warning" className="gap-1">
                        <IconShieldHalfFilled className="h-3.5 w-3.5" aria-hidden="true" />
                        {CATEGORY_LABEL[picked.category]}
                      </Badge>
                    ) : null}

                    {/* 剤形・規格 */}
                    <Select
                      label="剤形・規格"
                      value={form}
                      onChange={(e) => setForm(e.target.value)}
                    >
                      {picked.forms.map((f) => (
                        <option key={f} value={f}>
                          {f}
                        </option>
                      ))}
                    </Select>

                    {/* 用量 + ライブ用量フラグ */}
                    <div className="space-y-1.5">
                      <label htmlFor="draft-dose" className="text-sm font-medium leading-none">
                        1回量（{picked.unit}）
                      </label>
                      <div className="flex items-center gap-2">
                        <NumberInput
                          id="draft-dose"
                          value={dose}
                          onValueChange={setDose}
                          min={0}
                          step={picked.unit === "g" ? 0.5 : picked.usualLow < 5 ? 0.5 : 5}
                          aria-label={`1回量（${picked.unit}）`}
                          className="max-w-[160px]"
                        />
                        {draftDoseFlag ? <DoseRangeFlag result={draftDoseFlag} /> : null}
                      </div>
                      {draftDoseFlag ? (
                        <p
                          className={cn(
                            "text-xs",
                            draftDoseFlag.code === "OK"
                              ? "text-muted-foreground"
                              : draftDoseFlag.code === "H"
                                ? "text-destructive"
                                : "text-warning"
                          )}
                        >
                          常用量 {picked.usualLow}–{draftDoseFlag.effectiveHigh}
                          {picked.unit}
                          {draftDoseFlag.renalAdjusted ? (
                            <span className="font-medium">
                              {" "}
                              ／ eGFR {PATIENT.egfr} のため上限を腎調整
                            </span>
                          ) : null}
                        </p>
                      ) : null}
                    </div>

                    {/* 投与経路 */}
                    <fieldset className="space-y-1.5">
                      <legend className="text-sm font-medium leading-none">投与経路</legend>
                      <RadioGroup
                        value={route}
                        onValueChange={(v) => setRoute(v as Route)}
                        className="grid grid-cols-1 gap-1.5 pt-1"
                      >
                        {ROUTE_OPTIONS.map((r) => (
                          <RadioGroupItem
                            key={r.value}
                            value={r.value}
                            label={r.label}
                            description={r.hint}
                          />
                        ))}
                      </RadioGroup>
                    </fieldset>

                    {/* 用法 */}
                    <Select
                      label="用法"
                      value={freq}
                      onChange={(e) => setFreq(e.target.value)}
                    >
                      {FREQ_OPTIONS.map((f) => (
                        <option key={f} value={f}>
                          {f}
                        </option>
                      ))}
                    </Select>

                    {/* 日数 + 開始日 */}
                    <div className="grid grid-cols-2 gap-3">
                      <div className="space-y-1.5">
                        <label htmlFor="draft-days" className="text-sm font-medium leading-none">
                          日数
                        </label>
                        <NumberInput
                          id="draft-days"
                          value={days}
                          onValueChange={setDays}
                          min={1}
                          max={90}
                          step={1}
                          aria-label="日数"
                        />
                      </div>
                      <div className="space-y-1.5">
                        <label htmlFor="draft-start" className="text-sm font-medium leading-none">
                          開始日
                        </label>
                        <Input id="draft-start" value={TODAY} readOnly aria-label="開始日" />
                      </div>
                    </div>

                    {/* 追加前の安全プレビュー */}
                    {(draftAllergy.length > 0 || draftInteractions.length > 0) && (
                      <div className="space-y-2" aria-live="polite">
                        {draftAllergy.length > 0 ? (
                          <Alert variant="destructive">
                            <IconAlertTriangleFilled aria-hidden="true" />
                            <AlertTitle as="h3" className="text-sm">
                              アレルギー警告
                            </AlertTitle>
                            <AlertDescription className="text-xs">
                              {draftAllergy.map((h) => (
                                <span key={h.patientAllergy} className="block">
                                  {h.cross
                                    ? `${h.patientAllergy}との交差反応リスク（${h.drugKey}）`
                                    : `${h.patientAllergy}に該当`}
                                </span>
                              ))}
                              追加後に確認（acknowledge）が必要です。
                            </AlertDescription>
                          </Alert>
                        ) : null}
                        {draftInteractions.length > 0 ? (
                          <Alert
                            variant={
                              draftInteractions.some((i) => i.severity === "禁忌")
                                ? "destructive"
                                : "warning"
                            }
                          >
                            <IconAlertTriangleFilled aria-hidden="true" />
                            <AlertTitle as="h3" className="text-sm">
                              相互作用 {draftInteractions.length} 件
                            </AlertTitle>
                            <AlertDescription className="text-xs">
                              {draftInteractions.map((i) => (
                                <span key={i.withMed} className="block">
                                  [{i.severity}] {i.withMed}（{i.source}）
                                </span>
                              ))}
                            </AlertDescription>
                          </Alert>
                        ) : null}
                      </div>
                    )}

                    <Button
                      variant="primary"
                      className="w-full gap-1"
                      onClick={addLine}
                      disabled={dose <= 0}
                    >
                      <IconPencilPlus className="h-4 w-4" aria-hidden="true" />
                      処方セットに追加
                    </Button>
                  </div>
                ) : (
                  <p className="rounded-lg border border-dashed border-border bg-muted/30 px-3 py-6 text-center text-xs text-muted-foreground">
                    薬剤を選択すると用法用量の入力欄が表示されます。
                  </p>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </div>

      {/* ─────────────── 規制医薬品 2人署名 composer ─────────────── */}
      <CoSignDialog
        line={coSignFor}
        existing={coSignFor ? coSigns[coSignFor.key] : undefined}
        onOpenChange={(o) => {
          if (!o) setCoSignFor(null);
        }}
        onConfirm={(key, value) => {
          setCoSigns((m) => ({ ...m, [key]: value }));
          setCoSignFor(null);
          setSigned(false);
        }}
      />
    </main>
  );
}

// ── helpers ──────────────────────────────────────────────────────────────────
function addKey(s: Set<string>, k: string) {
  const next = new Set(s);
  next.add(k);
  return next;
}
function dropKey(s: Set<string>, k: string) {
  const next = new Set(s);
  next.delete(k);
  return next;
}

