// ── 処方セットのレビュー ───────────────────────────────────────────────────────
type LineEval = {
  line: RxLine;
  allergy: ReturnType<typeof allergyHits>;
  interactions: InteractionHit[];
  dose: ReturnType<typeof doseFlag>;
  needsAllergyAck: boolean;
  needsInteractionAck: boolean;
  needsDoseResolve: boolean;
  needsCoSign: boolean;
};

function OrderSetCard({
  evals,
  ackedAllergy,
  ackedInteraction,
  doseOverride,
  coSigns,
  signed,
  onRemove,
  onAckAllergy,
  onAckInteraction,
  onSetDoseOverride,
  onClearDoseOverride,
  onOpenCoSign,
}: {
  evals: LineEval[];
  ackedAllergy: Set<string>;
  ackedInteraction: Set<string>;
  doseOverride: Record<string, string>;
  coSigns: Record<string, CoSign>;
  signed: boolean;
  onRemove: (key: string) => void;
  onAckAllergy: (key: string) => void;
  onAckInteraction: (key: string) => void;
  onSetDoseOverride: (key: string, reason: string) => void;
  onClearDoseOverride: (key: string) => void;
  onOpenCoSign: (line: RxLine) => void;
}) {
  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle as="h2" className="flex items-center gap-2 text-lg">
          <IconClipboardList className="h-5 w-5" aria-hidden="true" />
          処方セット
          <Badge variant="outline" className="tabular-nums">
            {evals.length} 剤
          </Badge>
        </CardTitle>
        <CardDescription>
          各薬剤の用法用量と安全フラグ（アレルギー・相互作用・用量）を確認します。
        </CardDescription>
      </CardHeader>
      <CardContent className="px-2 sm:px-4">
        {evals.length === 0 ? (
          <EmptyState
            title="処方セットは空です"
            description="右の「処方薬の追加」から採用薬を検索して薬剤を追加してください。"
          />
        ) : (
          <div className="space-y-3">
            {/* 一覧テーブル（横スクロール可・375px対応） */}
            <div className="overflow-x-auto">
              <Table striped className="min-w-[640px]">
                <TableHeader>
                  <TableRow>
                    <TableHead scope="col" className="min-w-[150px]">
                      薬剤
                    </TableHead>
                    <TableHead scope="col" className="whitespace-nowrap">
                      用法用量
                    </TableHead>
                    <TableHead scope="col">用量判定</TableHead>
                    <TableHead scope="col">フラグ</TableHead>
                    <TableHead scope="col" className="text-right">
                      <span className="sr-only">操作</span>
                    </TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {evals.map((e) => {
                    const RouteIcon = ROUTE_ICON[e.line.route];
                    return (
                      <TableRow key={e.line.key}>
                        <TableHead
                          scope="row"
                          className="bg-transparent text-left align-top font-medium text-foreground"
                        >
                          <span className="font-semibold">{e.line.drug.generic}</span>
                          <span className="block text-xs font-normal text-muted-foreground">
                            {e.line.drug.brand} ・ {e.line.form}
                          </span>
                          {e.line.drug.category !== "通常" ? (
                            <Badge variant="warning" className="mt-1 gap-1">
                              <IconShieldHalfFilled className="h-3 w-3" aria-hidden="true" />
                              {e.line.drug.category}
                            </Badge>
                          ) : null}
                        </TableHead>
                        <TableCell className="align-top text-xs">
                          <span className="flex items-center gap-1 font-medium tabular-nums">
                            <RouteIcon className="h-3.5 w-3.5" aria-hidden="true" />
                            {e.line.dose}
                            {e.line.drug.unit} ・ {e.line.route}
                          </span>
                          <span className="block text-muted-foreground">
                            {e.line.freq} ・ {e.line.days}日分
                          </span>
                          <span className="block text-muted-foreground">
                            開始 {e.line.startDate}
                          </span>
                        </TableCell>
                        <TableCell className="align-top">
                          <DoseRangeFlag result={e.dose} />
                        </TableCell>
                        <TableCell className="align-top">
                          <div className="flex flex-col gap-1">
                            {e.needsAllergyAck ? (
                              <Badge variant="destructive" className="gap-1">
                                <IconAlertTriangleFilled
                                  className="h-3 w-3"
                                  aria-hidden="true"
                                />
                                アレルギー
                              </Badge>
                            ) : null}
                            {e.interactions.map((ix) => (
                              <Badge
                                key={ix.withMed}
                                variant={SEVERITY_TONE[ix.severity]}
                                className="gap-1"
                              >
                                <IconAlertTriangleFilled
                                  className="h-3 w-3"
                                  aria-hidden="true"
                                />
                                {ix.severity}
                              </Badge>
                            ))}
                            {e.needsCoSign ? (
                              <Badge
                                variant={coSigns[e.line.key] ? "success" : "warning"}
                                className="gap-1"
                              >
                                {coSigns[e.line.key] ? (
                                  <IconCircleCheck className="h-3 w-3" aria-hidden="true" />
                                ) : (
                                  <IconWritingSign className="h-3 w-3" aria-hidden="true" />
                                )}
                                2人署名{coSigns[e.line.key] ? "済" : "要"}
                              </Badge>
                            ) : null}
                            {!e.needsAllergyAck &&
                            e.interactions.length === 0 &&
                            !e.needsCoSign &&
                            e.dose.code === "OK" ? (
                              <Badge variant="success" className="gap-1">
                                <IconCircleCheck className="h-3 w-3" aria-hidden="true" />
                                チェッククリア
                              </Badge>
                            ) : null}
                          </div>
                        </TableCell>
                        <TableCell className="text-right align-top">
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => onRemove(e.line.key)}
                            disabled={signed}
                            aria-label={`${e.line.drug.generic} を処方セットから削除`}
                            className="gap-1 text-destructive"
                          >
                            <IconTrash className="h-3.5 w-3.5" aria-hidden="true" />
                            削除
                          </Button>
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </div>

            {/* 各薬剤の解決アクション（acknowledge / override / co-sign） */}
            {evals.map((e) => (
              <LineSafetyActions
                key={e.line.key}
                e={e}
                allergyAcked={ackedAllergy.has(e.line.key)}
                interactionAcked={ackedInteraction.has(e.line.key)}
                doseOverrideReason={doseOverride[e.line.key]}
                coSign={coSigns[e.line.key]}
                signed={signed}
                onAckAllergy={() => onAckAllergy(e.line.key)}
                onAckInteraction={() => onAckInteraction(e.line.key)}
                onSetDoseOverride={(r) => onSetDoseOverride(e.line.key, r)}
                onClearDoseOverride={() => onClearDoseOverride(e.line.key)}
                onOpenCoSign={() => onOpenCoSign(e.line)}
              />
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ── 1薬剤ぶんの安全解決アクション ──────────────────────────────────────────────
function LineSafetyActions({
  e,
  allergyAcked,
  interactionAcked,
  doseOverrideReason,
  coSign,
  signed,
  onAckAllergy,
  onAckInteraction,
  onSetDoseOverride,
  onClearDoseOverride,
  onOpenCoSign,
}: {
  e: LineEval;
  allergyAcked: boolean;
  interactionAcked: boolean;
  doseOverrideReason?: string;
  coSign?: CoSign;
  signed: boolean;
  onAckAllergy: () => void;
  onAckInteraction: () => void;
  onSetDoseOverride: (reason: string) => void;
  onClearDoseOverride: () => void;
  onOpenCoSign: () => void;
}) {
  const [overrideDraft, setOverrideDraft] = React.useState("");

  const contraindications = e.interactions.filter((i) => i.severity === "禁忌");
  const others = e.interactions.filter((i) => i.severity !== "禁忌");
  const hasAnything =
    e.needsAllergyAck ||
    e.interactions.length > 0 ||
    e.dose.code !== "OK" ||
    e.needsCoSign;
  if (!hasAnything) return null;

  return (
    <section
      aria-label={`${e.line.drug.generic} の安全チェック`}
      className="space-y-2 rounded-lg border border-border bg-card p-3"
    >
      <h3 className="flex items-center gap-1.5 text-sm font-semibold">
        <IconPill className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
        {e.line.drug.generic}（{e.line.drug.brand}）
      </h3>

      {/* アレルギー：assertive・acknowledgeable（blocking） */}
      {e.needsAllergyAck ? (
        <div aria-live="assertive">
          <Alert variant={allergyAcked ? "success" : "destructive"}>
            {allergyAcked ? (
              <IconCircleCheck aria-hidden="true" />
            ) : (
              <IconAlertTriangleFilled aria-hidden="true" />
            )}
            <AlertTitle as="h4" className="text-sm">
              アレルギー警告{allergyAcked ? "（確認済）" : "（処方をブロック）"}
            </AlertTitle>
            <AlertDescription className="space-y-2 text-xs">
              <div>
                {e.allergy.map((h) => (
                  <p key={h.patientAllergy}>
                    患者は <strong>{h.patientAllergy}</strong> アレルギー。
                    {h.cross
                      ? `本剤（${h.drugKey}）は交差反応のリスクがあります。`
                      : `本剤は当該系統に直接該当します。`}
                  </p>
                ))}
              </div>
              {!allergyAcked ? (
                <Checkbox
                  checked={false}
                  onCheckedChange={() => onAckAllergy()}
                  disabled={signed}
                  label="リスクを確認し、代替薬の検討または投与の判断を行ったうえで処方を続行する"
                />
              ) : (
                <p className="font-medium text-success-strong">
                  確認済み — {PRESCRIBER}（{NOW_LABEL}）
                </p>
              )}
            </AlertDescription>
          </Alert>
        </div>
      ) : null}

      {/* 禁忌相互作用：assertive・acknowledgeable（blocking） */}
      {contraindications.length > 0 ? (
        <div aria-live="assertive">
          <Alert variant={interactionAcked ? "success" : "destructive"}>
            {interactionAcked ? (
              <IconCircleCheck aria-hidden="true" />
            ) : (
              <IconBan aria-hidden="true" />
            )}
            <AlertTitle as="h4" className="text-sm">
              禁忌の相互作用{interactionAcked ? "（確認済）" : "（処方をブロック）"}
            </AlertTitle>
            <AlertDescription className="space-y-2 text-xs">
              <div>
                {contraindications.map((ix) => (
                  <p key={ix.withMed}>
                    <strong>{ix.withMed}</strong>（{ix.source}）との併用は禁忌。{ix.detail}
                  </p>
                ))}
              </div>
              {!interactionAcked ? (
                <Checkbox
                  checked={false}
                  onCheckedChange={() => onAckInteraction()}
                  disabled={signed}
                  label="禁忌を確認し、ベネフィットがリスクを上回ると判断して処方を続行する"
                />
              ) : (
                <p className="font-medium text-success-strong">
                  確認済み — {PRESCRIBER}（{NOW_LABEL}）
                </p>
              )}
            </AlertDescription>
          </Alert>
        </div>
      ) : null}

      {/* 中等度・重大（非禁忌）相互作用：warning・注意（non-blocking） */}
      {others.length > 0 ? (
        <Alert variant="warning">
          <IconAlertTriangleFilled aria-hidden="true" />
          <AlertTitle as="h4" className="text-sm">
            相互作用（要注意）
          </AlertTitle>
          <AlertDescription className="text-xs">
            {others.map((ix) => (
              <p key={ix.withMed}>
                [{ix.severity}] <strong>{ix.withMed}</strong>（{ix.source}）：{ix.detail}
              </p>
            ))}
          </AlertDescription>
        </Alert>
      ) : null}

      {/* 用量：過量(H)はブロック→理由付きoverride、過少(L)は注意 */}
      {e.dose.code === "H" ? (
        <Alert variant={doseOverrideReason ? "success" : "destructive"}>
          {doseOverrideReason ? (
            <IconCircleCheck aria-hidden="true" />
          ) : (
            <IconAlertTriangleFilled aria-hidden="true" />
          )}
          <AlertTitle as="h4" className="text-sm">
            用量過量{doseOverrideReason ? "（理由付きで許可）" : "（処方をブロック）"}
          </AlertTitle>
          <AlertDescription className="space-y-2 text-xs">
            <p>
              1回量 {e.line.dose}
              {e.line.drug.unit} は安全範囲（{e.line.drug.usualLow}–{e.dose.effectiveHigh}
              {e.line.drug.unit}
              {e.dose.renalAdjusted ? `、eGFR ${PATIENT.egfr} 腎調整後` : ""}）の上限を超えています。
            </p>
            {doseOverrideReason ? (
              <div className="flex items-center justify-between gap-2">
                <p className="font-medium text-success-strong">
                  オーバーライド理由：{doseOverrideReason}
                </p>
                <Button
                  size="sm"
                  variant="ghost"
                  onClick={onClearDoseOverride}
                  disabled={signed}
                >
                  取消
                </Button>
              </div>
            ) : (
              <div className="space-y-1.5">
                <label
                  htmlFor={`override-${e.line.key}`}
                  className="block text-xs font-medium"
                >
                  上限超過を許可する理由（必須）
                </label>
                <div className="flex flex-wrap gap-2">
                  <Input
                    id={`override-${e.line.key}`}
                    value={overrideDraft}
                    onChange={(ev) => setOverrideDraft(ev.target.value)}
                    placeholder="例：疼痛コントロール不十分のため増量"
                    disabled={signed}
                    className="min-w-[200px] flex-1"
                  />
                  <Button
                    size="sm"
                    variant="warning"
                    disabled={signed || overrideDraft.trim().length < 3}
                    onClick={() => onSetDoseOverride(overrideDraft.trim())}
                  >
                    理由付きで許可
                  </Button>
                </div>
              </div>
            )}
          </AlertDescription>
        </Alert>
      ) : e.dose.code === "L" ? (
        <Alert variant="warning">
          <IconAlertTriangleFilled aria-hidden="true" />
          <AlertTitle as="h4" className="text-sm">
            用量過少（要注意）
          </AlertTitle>
          <AlertDescription className="text-xs">
            1回量 {e.line.dose}
            {e.line.drug.unit} は常用量の下限（{e.line.drug.usualLow}
            {e.line.drug.unit}）を下回ります。効果不十分の可能性があります。
          </AlertDescription>
        </Alert>
      ) : null}

      {/* 規制医薬品：2人署名 */}
      {e.needsCoSign ? (
        <Alert variant={coSign ? "success" : "warning"}>
          {coSign ? (
            <IconCircleCheck aria-hidden="true" />
          ) : (
            <IconShieldHalfFilled aria-hidden="true" />
          )}
          <AlertTitle as="h4" className="text-sm">
            規制医薬品（{e.line.drug.category}）：2人署名{coSign ? "完了" : "必須"}
          </AlertTitle>
          <AlertDescription className="space-y-2 text-xs">
            <p>
              麻薬・向精神薬の処方には、処方医に加えて2人目（医師／薬剤師）の署名と理由が必要です。
              {coSign ? `（署名者：${coSign.signerId}／理由：${coSign.reason}）` : ""}
            </p>
            <div>
              <Button
                size="sm"
                variant={coSign ? "outline" : "warning"}
                disabled={signed}
                onClick={onOpenCoSign}
              >
                <IconWritingSign className="h-3.5 w-3.5" aria-hidden="true" />
                {coSign ? "2人署名を修正" : "2人署名を取得"}
              </Button>
            </div>
          </AlertDescription>
        </Alert>
      ) : null}
    </section>
  );
}

// ── サインオフ・アクション ─────────────────────────────────────────────────────
function SignOffCard({
  lines,
  blockers,
  canSign,
  signed,
  onSign,
  onClear,
}: {
  lines: RxLine[];
  blockers: { kind: string; line: RxLine; detail: string }[];
  canSign: boolean;
  signed: boolean;
  onSign: () => void;
  onClear: () => void;
}) {
  // role="alert" な Alert は挿入時のみ発話するので、blocker 件数で remount して読み直す。
  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle as="h2" className="flex items-center gap-2 text-lg">
          <IconWritingSign className="h-5 w-5" aria-hidden="true" />
          処方確定・署名
        </CardTitle>
        <CardDescription>
          すべての安全チェック（アレルギー・禁忌・過量の解決、規制医薬品の2人署名）を満たすと署名できます。
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        {signed ? (
          <Alert variant="success" aria-live="polite">
            <IconCircleCheck aria-hidden="true" />
            <AlertTitle as="h3">処方を確定・署名しました</AlertTitle>
            <AlertDescription>
              {PRESCRIBER} が {NOW_LABEL} に {lines.length} 剤の処方セットを電子署名しました。薬剤部へ送信されます。
            </AlertDescription>
          </Alert>
        ) : blockers.length > 0 ? (
          <div key={blockers.length} aria-live="assertive">
            <Alert variant="destructive">
              <IconLock aria-hidden="true" />
              <AlertTitle as="h3">署名できません（未解決 {blockers.length} 件）</AlertTitle>
              <AlertDescription>
                <ul className="mt-1 space-y-1">
                  {blockers.map((b, i) => (
                    <li key={`${b.line.key}-${b.kind}-${i}`} className="flex items-start gap-1.5">
                      <Badge variant="outline" className="mt-0.5 shrink-0">
                        {b.kind}
                      </Badge>
                      <span>{b.detail}</span>
                    </li>
                  ))}
                </ul>
              </AlertDescription>
            </Alert>
          </div>
        ) : lines.length > 0 ? (
          <Alert variant="success" aria-live="polite">
            <IconCircleCheck aria-hidden="true" />
            <AlertTitle as="h3">安全チェック クリア</AlertTitle>
            <AlertDescription>
              {lines.length} 剤すべての安全チェックを満たしました。処方を確定・署名できます。
            </AlertDescription>
          </Alert>
        ) : null}

        <div className="flex flex-wrap items-center gap-2">
          <Button
            variant="primary"
            size="lg"
            disabled={!canSign}
            onClick={onSign}
            className="gap-1"
          >
            {canSign ? (
              <IconWritingSign className="h-5 w-5" aria-hidden="true" />
            ) : (
              <IconLock className="h-5 w-5" aria-hidden="true" />
            )}
            {signed ? "署名済" : "処方を確定・署名"}
          </Button>
          <Button variant="outline" disabled={signed || lines.length === 0}>
            一時保存
          </Button>
          <Button
            variant="ghost"
            disabled={lines.length === 0}
            onClick={onClear}
            className="gap-1 text-destructive"
          >
            <IconTrash className="h-4 w-4" aria-hidden="true" />
            中止（破棄）
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

// ── 規制医薬品 2人署名 Dialog（HAND-ROLLED co-sign composer） ───────────────────
function CoSignDialog({
  line,
  existing,
  onOpenChange,
  onConfirm,
}: {
  line: RxLine | null;
  existing?: CoSign;
  onOpenChange: (open: boolean) => void;
  onConfirm: (key: string, value: CoSign) => void;
}) {
  const [signerId, setSignerId] = React.useState("");
  const [reason, setReason] = React.useState("");
  const [attest, setAttest] = React.useState({ indication: false, dose: false, regulation: false });

  React.useEffect(() => {
    if (line) {
      setSignerId(existing?.signerId ?? "");
      setReason(existing?.reason ?? "");
      setAttest({ indication: false, dose: false, regulation: false });
    }
  }, [line, existing]);

  const sameAsPrimary = signerId.trim() === PRESCRIBER;
  const allAttested = attest.indication && attest.dose && attest.regulation;
  const canConfirm =
    signerId.trim().length >= 2 && reason.trim().length >= 3 && allAttested && !sameAsPrimary;

  return (
    <Dialog open={line !== null} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>規制医薬品の2人署名</DialogTitle>
          <DialogDescription>
            {line
              ? `${line.drug.generic}（${line.drug.brand}）${line.dose}${line.drug.unit}・${line.route} ／ ${line.drug.category}`
              : ""}
            の処方には、処方医（{PRESCRIBER}）に加えて2人目の医師または薬剤師の署名が必要です。
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          <div className="space-y-1.5">
            <label htmlFor="cosign-signer" className="text-sm font-medium">
              2人目署名者（医師 / 薬剤師ID・氏名）
            </label>
            <Input
              id="cosign-signer"
              value={signerId}
              onChange={(e) => setSignerId(e.target.value)}
              placeholder="例：鈴木 薬剤師"
              aria-invalid={sameAsPrimary || undefined}
              aria-describedby={sameAsPrimary ? "cosign-signer-err" : undefined}
            />
            {sameAsPrimary ? (
              <p id="cosign-signer-err" role="alert" className="text-xs font-medium text-destructive">
                処方医（{PRESCRIBER}）と同一人物では2人署名になりません。別の署名者を指定してください。
              </p>
            ) : null}
          </div>

          <div className="space-y-1.5">
            <label htmlFor="cosign-reason" className="text-sm font-medium">
              処方理由・適応（必須）
            </label>
            <Textarea
              id="cosign-reason"
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder="例：がん性疼痛に対する疼痛緩和。NRS 7/10。"
              rows={2}
            />
          </div>

          <fieldset className="space-y-2">
            <legend className="mb-1 text-sm font-medium">確認事項（2人目が独立に確認）</legend>
            <Checkbox
              checked={attest.indication}
              onCheckedChange={(v) => setAttest((a) => ({ ...a, indication: v }))}
              label="適応・必要性が妥当であることを確認した"
            />
            <Checkbox
              checked={attest.dose}
              onCheckedChange={(v) => setAttest((a) => ({ ...a, dose: v }))}
              label="用量・用法が患者（腎機能含む）に対して適切であることを確認した"
            />
            <Checkbox
              checked={attest.regulation}
              onCheckedChange={(v) => setAttest((a) => ({ ...a, regulation: v }))}
              label="麻薬・向精神薬の管理規程に基づき記録することを確認した"
            />
          </fieldset>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            キャンセル
          </Button>
          <Button
            variant="primary"
            disabled={!canConfirm || !line}
            onClick={() =>
              line && onConfirm(line.key, { signerId: signerId.trim(), reason: reason.trim() })
            }
          >
            <IconWritingSign className="h-4 w-4" aria-hidden="true" />
            2人署名を確定
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

// 処方オーダ domain model + the safety engines (dose-range flag, allergy match,
// drug-drug interaction).
//
// NOTE (FINDINGS-56): @gunjo/ui ships NO value-vs-reference-range primitive, so
// the dose-range flag engine (`doseFlag`) below is hand-rolled — the SAME gap the
// #54 vitals and #55 labs screens hit (this is the 3rd occurrence). The pure
// `doseFlag()` helper + the `DoseRangeFlag` presentational badge are what an ideal
// `flagValue()` / `<ReferenceValue>` in the library would ship. The renal
// adjustment (max dose bends with the patient's eGFR) is just a parameter to the
// same value+range shape.

