// ── Formulary (採用薬) ───────────────────────────────────────────────────────
export interface FormularyDrug {
  id: string;
  /** 一般名 */
  generic: string;
  /** 商品名 */
  brand: string;
  category: Category;
  /** 既定の剤形・規格 */
  forms: string[];
  /** 既定の投与経路 */
  defaultRoute: Route;
  /** 単位（mg / 錠 / mL …） */
  unit: string;
  /** 常用量（1回量）の安全範囲。renalMaxFactor があれば eGFR 低下時に上限を縮める。 */
  usualLow: number;
  usualHigh: number;
  /** eGFR が renalEgfrCutoff 未満なら上限に renalMaxFactor を掛ける（腎排泄薬）。 */
  renalEgfrCutoff?: number;
  renalMaxFactor?: number;
  /** 既定の用法 */
  defaultFreq: string;
  /** アレルギー照合キー（この薬が該当する系統） — 交差反応含む。 */
  allergyKeys: string[];
  /** 相互作用：併用薬名 → 重大度・内容。 */
  interactions: Interaction[];
  /** 検索補助語 */
  keywords: string[];
}

export type InteractionSeverity = "禁忌" | "重大" | "中等度";
export interface Interaction {
  /** 併用薬（一般名） */
  withMed: string;
  severity: InteractionSeverity;
  detail: string;
}

