// ── Order-set line ───────────────────────────────────────────────────────────
export interface RxLine {
  /** 一意キー */
  key: string;
  drug: FormularyDrug;
  /** 剤形・規格 */
  form: string;
  /** 1回量 */
  dose: number;
  route: Route;
  /** 用法 */
  freq: string;
  /** 日数 */
  days: number;
  /** 開始日 */
  startDate: string;
}

// ── Safety engine 1: dose-range flag (HAND-ROLLED, 3rd occurrence) ────────────
export type DoseFlagCode = "OK" | "H" | "L";
export interface DoseFlagResult {
  code: DoseFlagCode;
  /** 表示用ラベル（過量/過少/範囲内） */
  label: string;
  tone: "success" | "warning" | "destructive";
  /** スクリーンリーダー向け完全文。 */
  srText: string;
  /** この患者に適用される実効上限（腎調整後）。 */
  effectiveHigh: number;
  effectiveLow: number;
  /** 腎調整が掛かったか。 */
  renalAdjusted: boolean;
}

/**
 * PURE dose-range engine — entered dose vs the drug's 常用量 (safe range),
 * renal-adjusted against the patient's eGFR. This is the function an ideal
 * @gunjo/ui `flagValue()` / `<ReferenceValue>` would expose.
 */
export function doseFlag(drug: FormularyDrug, dose: number, egfr: number): DoseFlagResult {
  let high = drug.usualHigh;
  const low = drug.usualLow;
  let renalAdjusted = false;
  if (
    drug.renalEgfrCutoff != null &&
    drug.renalMaxFactor != null &&
    drug.renalMaxFactor < 1 &&
    egfr < drug.renalEgfrCutoff
  ) {
    high = Math.round(drug.usualHigh * drug.renalMaxFactor * 100) / 100;
    renalAdjusted = true;
  }
  const u = drug.unit;
  const rangeText = `常用量 ${low}–${high}${u}${renalAdjusted ? `（eGFR ${egfr} のため腎調整後）` : ""}`;

  if (dose > high) {
    return {
      code: "H",
      label: "過量 (H)",
      tone: "destructive",
      srText: `過量。1回量 ${dose}${u} は ${rangeText} の上限を超えています。減量または理由付きオーバーライドが必要です。`,
      effectiveHigh: high,
      effectiveLow: low,
      renalAdjusted,
    };
  }
  if (dose < low) {
    return {
      code: "L",
      label: "過少 (L)",
      tone: "warning",
      srText: `過少。1回量 ${dose}${u} は ${rangeText} の下限を下回ります。効果不十分の可能性。`,
      effectiveHigh: high,
      effectiveLow: low,
      renalAdjusted,
    };
  }
  return {
    code: "OK",
    label: "範囲内",
    tone: "success",
    srText: `範囲内。1回量 ${dose}${u} は ${rangeText} に収まっています。`,
    effectiveHigh: high,
    effectiveLow: low,
    renalAdjusted,
  };
}

// ── Safety engine 2: allergy match ───────────────────────────────────────────
export interface AllergyHit {
  /** 患者のアレルギー歴の項目 */
  patientAllergy: string;
  /** この薬の該当系統 */
  drugKey: string;
  /** 直接一致か交差反応か */
  cross: boolean;
}

export function allergyHits(drug: FormularyDrug, patient: Patient): AllergyHit[] {
  const hits: AllergyHit[] = [];
  for (const key of drug.allergyKeys) {
    for (const pa of patient.allergies) {
      if (key === pa) {
        hits.push({ patientAllergy: pa, drugKey: key, cross: false });
      } else if (
        // 交差反応：セフェム系 ↔ ペニシリン系
        (key === "セフェム系" && pa === "ペニシリン系") ||
        (key === "ペニシリン系" && pa === "セフェム系")
      ) {
        hits.push({ patientAllergy: pa, drugKey: key, cross: true });
      }
    }
  }
  // de-dup by (patientAllergy + cross)
  const seen = new Set<string>();
  return hits.filter((h) => {
    const k = `${h.patientAllergy}|${h.cross}`;
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });
}

// ── Safety engine 3: drug-drug interaction (vs active meds + other lines) ─────
export interface InteractionHit {
  severity: InteractionSeverity;
  withMed: string;
  detail: string;
  /** 併用薬リスト由来か、処方セット内の別の薬由来か */
  source: "併用薬" | "処方セット内";
}

export function interactionHits(
  drug: FormularyDrug,
  patient: Patient,
  otherLineGenerics: string[]
): InteractionHit[] {
  const hits: InteractionHit[] = [];
  for (const ix of drug.interactions) {
    if (patient.activeMeds.includes(ix.withMed)) {
      hits.push({ ...ix, source: "併用薬" });
    } else if (otherLineGenerics.includes(ix.withMed)) {
      hits.push({ ...ix, source: "処方セット内" });
    }
  }
  return hits;
}

